document.addEventListener("DOMContentLoaded",function(){if(document.getElementById("uap-map")&&"undefined"!=typeof L){var a=L.map("uap-map",{scrollWheelZoom:!1}).setView([25,-30],2);L.tileLayer("https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",{attribution:'&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',subdomains:"abcd",maxZoom:19}).addTo(a);var l=[{lat:33.3943,lng:-104.523,label:"Roswell Incident, 1947"},{lat:52.0896,lng:1.4274,label:"Rendlesham Forest, 1980"},{lat:33.4484,lng:-112.074,label:"Phoenix Lights, 1997"},{lat:32,lng:-119,label:"Nimitz Tic Tac, 2004"},{lat:35.6892,lng:51.389,label:"Tehran UFO, 1976"},{lat:50.5039,lng:4.4699,label:"Belgium Wave, 1989"},{lat:41.9742,lng:-87.9073,label:"O'Hare Airport, 2006"},{lat:61.2181,lng:-149.9003,label:"JAL Flight 1628, 1986"},{lat:43.4716,lng:-65.7458,label:"Shag Harbour, 1967"},{lat:32.2182,lng:-98.2023,label:"Stephenville, 2008"}].map(function(l){return L.circleMarker([l.lat,l.lng],{radius:9,color:"#a9812f",weight:2,fillColor:"#d4af37",fillOpacity:.9}).bindPopup("<strong>"+l.label+"</strong>").addTo(a)}),t=L.featureGroup(l);a.fitBounds(t.getBounds().pad(.25))}});